import type { TrainID } from './train';

export type TaskID = `T${string}`;

export interface Task {
  id: TaskID;
  trainId: TrainID;
  start: number; // epoch millis
  end: number;   // epoch millis
  durationH: number;
  resource: string; // e.g., Pit1, TV16
  type: 'routine' | 'overhaul' | 'bottleneck' | 'inspection' | 'lathe';
  density?: number; // for macro view aggregation
  conflict?: boolean;
  deps?: TaskID[]; // dependencies (predecessors)
}

export interface Conflict {
  id: string;
  trainId: TrainID;
  taskIds: TaskID[];
  start: number;
  end: number;
  level: 'warning' | 'critical';
}

