import seedrandom from 'seedrandom';
import { addYears, addDays } from 'date-fns';
import type { Train, TrainID } from '../entities/train';
import type { Task, TaskID, Conflict } from '../entities/task';
import { DAY, HOUR } from '../utils/time';

export interface MockDataset {
  trains: Train[];
  tasks: Task[];
  conflicts: Conflict[];
  startTime: number; // start of macro timeline
  endTime: number;   // end of macro timeline
}

export function generateMockData(seed = 'mms-seed', years = 10): MockDataset {
  const rng = seedrandom(seed);

  const start = new Date();
  start.setMonth(0, 1); // Jan 1 this year
  start.setHours(0, 0, 0, 0);
  const end = addYears(start, years);

  const trains: Train[] = Array.from({ length: 50 }, (_, i) => ({
    id: (`T${(i + 1).toString().padStart(3, '0')}`) as TrainID,
    label: `T${(i + 1).toString().padStart(3, '0')}`,
    lineIndex: i,
  }));

  const tasks: Task[] = [];

  // Generate a dense DNA-like pattern across years
  for (const train of trains) {
    let cursor = start.getTime();
    while (cursor < end.getTime()) {
      // Alternating routine vs overhaul stripes
      const isOverhaul = Math.floor((cursor - start.getTime()) / (DAY * 20)) % 7 === 0;
      const blockDays = isOverhaul ? 7 + Math.floor(rng() * 5) : 2 + Math.floor(rng() * 3);
      const duration = blockDays * DAY;
      const jitter = (rng() - 0.5) * DAY * 2;
      const begin = Math.max(start.getTime(), cursor + jitter);
      const task: Task = {
        id: (`T${train.id}-${begin}`) as TaskID,
        trainId: train.id,
        start: begin,
        end: begin + duration,
        durationH: Math.round(duration / HOUR),
        resource: ['Pit 1', 'Pit 2', 'Pit 3', 'TV16'][Math.floor(rng() * 4)],
        type: isOverhaul ? 'overhaul' : (rng() > 0.8 ? 'bottleneck' : 'routine'),
        deps: [],
      };
      tasks.push(task);
      cursor = begin + duration + DAY * (isOverhaul ? 10 : 3);
    }
  }

  // Inject dependencies inside a 6–8 week operational window around October
  const october = new Date(start.getFullYear(), 9, 1).getTime();
  const opStart = october - 14 * DAY;
  const opEnd = october + 42 * DAY;
  const opWindowTasks = tasks.filter(t => t.start >= opStart && t.end <= opEnd);
  for (let i = 0; i < opWindowTasks.length; i++) {
    if (rng() < 0.15 && i + 1 < opWindowTasks.length) {
      const a = opWindowTasks[i];
      const b = opWindowTasks[i + 1];
      if (a.trainId === b.trainId && a.end + DAY < b.start) {
        // create dependency chain
        b.deps = [...(b.deps || []), a.id];
      }
    }
  }

  // Conflicts: force overlaps in micro window
  const conflicts: Conflict[] = [];
  for (const train of trains) {
    const local = opWindowTasks.filter(t => t.trainId === train.id).sort((a, b) => a.start - b.start);
    for (let i = 0; i < local.length - 1; i++) {
      const a = local[i];
      const b = local[i + 1];
      if (a.end > b.start && rng() > 0.5) {
        // overlap -> conflict
        a.conflict = true;
        b.conflict = true;
        conflicts.push({
          id: `${train.id}-${a.id}-${b.id}`,
          trainId: train.id,
          taskIds: [a.id, b.id],
          start: Math.max(a.start, b.start),
          end: Math.min(a.end, b.end),
          level: rng() > 0.6 ? 'critical' : 'warning',
        });
      }
    }
  }

  return {
    trains,
    tasks,
    conflicts,
    startTime: start.getTime(),
    endTime: end.getTime(),
  };
}

// Heatmap aggregation: encode as width x height DataTexture grid (time x trains)
export function buildHeatmapGrid(dataset: MockDataset, columns = 4096): {
  width: number; height: number; data: Uint8Array
} {
  const width = columns;
  const height = dataset.trains.length;
  const total = dataset.endTime - dataset.startTime;
  const data = new Uint8Array(width * height);

  const pxPerMs = width / total;

  for (const task of dataset.tasks) {
    const y = dataset.trains.findIndex(t => t.id === task.trainId);
    const x0 = Math.max(0, Math.floor((task.start - dataset.startTime) * pxPerMs));
    const x1 = Math.min(width - 1, Math.ceil((task.end - dataset.startTime) * pxPerMs));
    for (let x = x0; x <= x1; x++) {
      const idx = y * width + x;
      data[idx] = Math.min(255, data[idx] + (task.type === 'overhaul' ? 20 : 8));
    }
  }
  return { width, height, data };
}

