import React from 'react';
import { clsx } from 'clsx';

export function Button({ className, ...props }: React.ButtonHTMLAttributes<HTMLButtonElement>) {
  return (
    <button
      className={clsx(
        'rounded-md bg-blue-700 hover:bg-blue-800 text-white px-3 py-1.5 shadow-sm focus:outline-none focus:ring-2 focus:ring-blue-400',
        className,
      )}
      {...props}
    />
  );
}

export function Card({ className, ...props }: React.HTMLAttributes<HTMLDivElement>) {
  return (
    <div
      className={clsx(
        'rounded-lg bg-white/90 shadow-md ring-1 ring-black/5 backdrop-blur p-3',
        className,
      )}
      {...props}
    />
  );
}

export function Badge({ className, color = 'zinc', children }: { className?: string; color?: 'zinc'|'red'|'blue'|'amber'|'green'; children: React.ReactNode }) {
  const colorCls = {
    zinc: 'bg-zinc-200 text-zinc-700',
    red: 'bg-red-100 text-red-700',
    blue: 'bg-blue-100 text-blue-700',
    amber: 'bg-amber-100 text-amber-800',
    green: 'bg-green-100 text-green-700'
  }[color];
  return <span className={clsx('inline-flex items-center rounded px-2 py-0.5 text-xs font-medium', colorCls, className)}>{children}</span>;
}

export * from './train-list-item';

