import * as React from 'react';
import { Html } from '@react-three/drei';
import { Line2, LineMaterial, LineGeometry } from 'three-stdlib';
import { Vector3, CatmullRomCurve3 } from 'three';
import { usePlanning, usePlanningSelector } from '../state/world-machine';

export function MicroLayer(){
  const dataset = usePlanningSelector(s => s.schedule.dataset);
  const [viewport] = usePlanning('viewport');

  // subset 4-8 weeks around Oct for dense DOM overlay
  const start = dataset.startTime + (9*30*24*60*60*1000) - (14*24*60*60*1000);
  const end = start + 56*24*60*60*1000;
  const micro = React.useMemo(()=>dataset.tasks.filter(t=>t.start>=start && t.end<=end),[dataset]);

  return (
    <group>
      {/* Dependencies as curved lines behind */}
      {micro.map((t,i)=> t.deps?.map((depId, j)=>{
        const dep = micro.find(x=>x.id===depId); if(!dep) return null;
        const y0 = dataset.trains.findIndex(tr=>tr.id===dep.trainId)*2, y1 = dataset.trains.findIndex(tr=>tr.id===t.trainId)*2;
        const x0 = (dep.end - dataset.startTime) / (24*60*60*1000);
        const x1 = (t.start - dataset.startTime) / (24*60*60*1000);
        const p0 = new Vector3(x0, y0, -0.1);
        const p3 = new Vector3(x1, y1, -0.1);
        const curve = new CatmullRomCurve3([p0, new Vector3((x0+x1)/2, y0, -0.1), new Vector3((x0+x1)/2, y1, -0.1), p3]);
        const points = curve.getPoints(16);
        const positions: number[] = [];
        points.forEach(p=>{ positions.push(p.x, p.y, p.z); });
        const g = new LineGeometry(); g.setPositions(positions);
        const m = new LineMaterial({ color: 0x64748b, linewidth: 2, worldUnits: true });
        const line = new Line2(g, m);
        return <primitive key={`${i}-${j}`} object={line} />;
      }))}

      {/* Task cards as DOM overlay */}
      {micro.slice(0, 300).map(t=>{
        const x = (t.start - dataset.startTime) / (24*60*60*1000);
        const w = Math.max(2, (t.end - t.start) / (24*60*60*1000));
        const y = dataset.trains.findIndex(tr=>tr.id===t.trainId) * 2;
        const handleKeyDown = (ev: React.KeyboardEvent) => {
          if (ev.key === 'Enter' || ev.key === ' ') {
            ev.preventDefault();
            console.log('Task selected:', t.id);
            // TODO: dispatch selection action
          }
        };
        return (
          <Html key={t.id} position={[x + w/2, y, 0]} transform occlude={false} zIndexRange={[0,0]}>
            <div 
              tabIndex={0} 
              role="button"
              aria-label={`Task ${t.id}, ${t.durationH} hours, ${t.resource}${t.conflict ? ', has conflict' : ''}`}
              onKeyDown={handleKeyDown}
              onClick={() => console.log('Task clicked:', t.id)}
              className={`select-none rounded-md border ${t.conflict? 'border-red-500 bg-red-50' : 'border-zinc-300 bg-white'} shadow-sm px-2 py-1 min-w-40 cursor-pointer hover:ring-2 hover:ring-blue-400 focus:ring-2 focus:ring-blue-500 focus:outline-none`}
            > 
              <div className="flex items-center gap-2">
                {t.conflict && <span className="text-red-600" aria-label="conflict">⚠︎</span>}
                <div className="text-xs font-semibold text-zinc-800">{t.id.slice(0,12)}</div>
              </div>
              <div className="text-[10px] text-zinc-500">{t.durationH}h • {t.resource}</div>
            </div>
          </Html>
        );
      })}
    </group>
  );
}

