// Heatmap fragment shader: samples a single-channel DataTexture where R=occupancy density [0..1]
precision highp float;

uniform sampler2D uTex;
uniform vec2 uTexSize; // width, height
uniform vec2 uViewport; // width, height (world units -> normalized in vertex)
varying vec2 vUv;

vec3 ramp(float t){
  // Yellow -> Orange -> Red ramp
  vec3 a = vec3(1.0, 0.95, 0.5); // light yellow
  vec3 b = vec3(1.0, 0.6, 0.0);  // orange
  vec3 c = vec3(0.85, 0.0, 0.0); // red
  if (t < 0.5) return mix(a, b, smoothstep(0.0, 0.5, t));
  return mix(b, c, smoothstep(0.5, 1.0, t));
}

void main(){
  vec2 uv = vUv;
  float d = texture2D(uTex, uv).r; // 0..1
  // slight vignette for contrast
  float vig = 0.9 + 0.1 * (1.0 - distance(uv, vec2(0.5)));
  vec3 col = ramp(d) * vig;
  gl_FragColor = vec4(col, 1.0);
}

