import * as React from 'react';
import { useThree } from '@react-three/fiber';
import { OrthographicCamera } from 'three';
import { usePlanning, PlanningActions } from '../state/world-machine';

// Proportional frustum constants: 1 day = ~10px at zoom 1, 1 train row = 24px
const PX_PER_DAY = 10;
const PX_PER_TRAIN = 24;
const ASPECT_RATIO = PX_PER_DAY / PX_PER_TRAIN; // time (X) vs fleet (Y)

export function CameraRig() {
  const [viewport, actions] = usePlanning('viewport');
  const { width, height, zoom } = viewport;
  const setViewport = PlanningActions.viewport.setViewport;
  const setCamera = PlanningActions.viewport.setCamera;

  const { camera, size } = useThree();

  React.useEffect(() => {
    const cam = camera as OrthographicCamera;
    cam.zoom = zoom;

    // Proportional frustum: maintain time vs fleet ratio
    // Horizontal represents days (time), vertical represents trains (fleet)
    const worldWidth = size.width / (PX_PER_DAY * zoom);
    const worldHeight = size.height / (PX_PER_TRAIN * zoom);

    cam.left = -worldWidth / 2;
    cam.right = worldWidth / 2;
    cam.top = worldHeight / 2;
    cam.bottom = -worldHeight / 2;

    cam.position.x = viewport.x;
    cam.position.y = viewport.y;
    cam.updateProjectionMatrix();
    actions.viewport.setViewport({ width: size.width, height: size.height });
  }, [camera, size.width, size.height, zoom, viewport.x, viewport.y]);

  // Pointer interactions
  const last = React.useRef<{x:number;y:number}|null>(null);
  React.useEffect(() => {
    function onWheel(ev: WheelEvent) {
      const dz = -ev.deltaY * 0.001;
      actions.viewport.zoomBy({ dz });
    }
    function onPointerDown(ev: PointerEvent) { last.current = { x: ev.clientX, y: ev.clientY }; }
    function onPointerMove(ev: PointerEvent) {
      if (!last.current || !(ev.buttons & 1)) return;
      const dx = ev.clientX - last.current.x; const dy = ev.clientY - last.current.y;
      last.current = { x: ev.clientX, y: ev.clientY };
      const z = (camera as OrthographicCamera).zoom || 1;
      actions.viewport.panBy({ dx: -dx / z, dy: dy / z });
    }
    function onPointerUp(){ last.current = null; }
    const root = (document.getElementById('gl-root'))!;
    root.addEventListener('wheel', onWheel, { passive: true });
    root.addEventListener('pointerdown', onPointerDown);
    root.addEventListener('pointermove', onPointerMove);
    root.addEventListener('pointerup', onPointerUp);
    return () => {
      root.removeEventListener('wheel', onWheel);
      root.removeEventListener('pointerdown', onPointerDown);
      root.removeEventListener('pointermove', onPointerMove);
      root.removeEventListener('pointerup', onPointerUp);
    }
  }, [actions.viewport]);

  return null;
}

