import React from 'react';
import { TrainListItem } from '@mms/ui';
import { usePlanning, usePlanningSelector } from '@mms/gl-engine';

const ROW = 24;

export function TrainList(){
  const trains = usePlanningSelector(s => s.schedule.dataset.trains);
  const [viewport, actions] = usePlanning('viewport');
  const ref = React.useRef<HTMLDivElement>(null);

  // Sync DOM scroll -> camera Y
  const onScroll = React.useCallback(() => {
    const el = ref.current!;
    const y = -el.scrollTop / ROW;
    actions.viewport.setCamera({ y });
  }, [actions.viewport]);

  // Sync camera Y -> DOM scroll
  React.useEffect(() => {
    const el = ref.current!;
    el.scrollTop = -viewport.y * ROW;
  }, [viewport.y]);

  return (
    <div ref={ref} onScroll={onScroll} className="divide-y divide-zinc-200 overflow-auto h-full">
      {trains.map(t=> <TrainListItem key={t.id} id={t.label} />)}
    </div>
  );
}

