import React from 'react';
import { usePlanning, usePlanningSelector } from '@mms/gl-engine';
import { buildHeatmapGrid } from '@mms/domain';

function ramp(t:number){
  const a = [1.0, 0.95, 0.5];
  const b = [1.0, 0.6, 0.0];
  const c = [0.85, 0.0, 0.0];
  const mix = (x:number,y:number,a:number)=>x*(1-a)+y*a;
  if (t<0.5){
    const k=(t-0)/(0.5-0); return [mix(a[0],b[0],k),mix(a[1],b[1],k),mix(a[2],b[2],k)];
  }
  const k=(t-0.5)/(0.5); return [mix(b[0],c[0],k),mix(b[1],c[1],k),mix(b[2],c[2],k)];
}

export function TimeScrubber(){
  const dataset = usePlanningSelector(s => s.schedule.dataset);
  const [viewport, actions] = usePlanning('viewport');
  const totalDays = Math.round((dataset.endTime - dataset.startTime) / (24*60*60*1000));

  const grid = React.useMemo(()=>buildHeatmapGrid(dataset, 1024),[dataset]);
  const bins = React.useMemo(()=>{
    const sums = new Float32Array(grid.width);
    for(let x=0;x<grid.width;x++){
      let s=0; for(let y=0;y<grid.height;y++){ s += grid.data[y*grid.width + x]; }
      sums[x]=s/(255*grid.height);
    }
    return sums;
  },[grid]);

  function onInput(ev: React.ChangeEvent<HTMLInputElement>){
    const d = Number(ev.target.value);
    actions.viewport.setCamera({ x: -d, y: viewport.y });
  }

  return (
    <div className="h-full flex items-center gap-4 px-4">
      <div className="text-xs text-zinc-600">Minimap</div>
      <div className="relative w-full h-12 overflow-hidden rounded-md bg-white">
        <svg viewBox={`0 0 ${grid.width} 48`} className="absolute inset-0 w-full h-full">
          {Array.from({length: grid.width}).map((_,x)=>{
            const v = Math.min(1, Math.max(0, bins[x]));
            const [r,g,b] = ramp(v);
            const h = v*48;
            return <rect key={x} x={x} y={48-h} width={1} height={h} fill={`rgb(${r*255},${g*255},${b*255})`} />
          })}
        </svg>
        <div className="absolute inset-0 flex items-center px-2">
          <input aria-label="timeline" type="range" min={0} max={totalDays} step={1} className="w-full" onChange={onInput} />
        </div>
      </div>
    </div>
  );
}

